custom_css:
.row .form-group .form-control,
.row .form-group .multiselect__tags
/*,.row .form-group textarea */
{
    height: 40px;
    min-height: 40px;
    box-sizing: border-box;
}
/* Style for the header */
[selector='comments-table'] {
    background-color: #f8f9fa; /* Light background */
    font-weight: bold;
    height: 40px;
    border-bottom: 2px solid #dee2e6;
    /*padding: 10px 0;*/
}

[selector='comments-table'] > .col-sm-3,
[selector='comments-table'] > .col-sm-2 {
    text-align: center;
    border-right: 1px solid #dee2e6;
    padding: 5px;
}

[selector='comments-table'] > .col-sm-3:last-child,
[selector='comments-table'] > .col-sm-2:last-child {
    border-right: none;
}

/* Style for the content */
[selector='comments-table-content'] {
    background-color: #ffffff; /* White background for rows */
    border-bottom: 1px solid #dee2e6; /* Bottom line between rows */
    padding: 10px 0;
}

[selector='comments-table-content'] > .col-sm-3,
[selector='comments-table-content'] > .col-sm-2 {
    text-align: left; /* Align text to the left */
    padding: 5px;
    border-right: 1px solid #dee2e6; /* Separation between columns */
}

[selector='comments-table-content'] > .col-sm-3:last-child,
[selector='comments-table-content'] > .col-sm-2:last-child {
    border-right: none; /* Remove right border on the last column */
}

/* Styles for input fields */
[selector='comments-table-content'] input.form-control,
[selector='comments-table-content'] textarea.form-control {
    border: 1px solid #ced4da; /* Standard border */
    border-radius: 4px; /* Rounded corners */
    padding: 5px;
    background-color: #f8f9fa; /* Slightly gray background */
}
